SELECT AVG(version_count) AS average_versions
FROM (
  SELECT tv.template_id, COUNT(tv.version_id) AS version_count
  FROM template_versions tv
  WHERE tv.template_id IN (
    SELECT DISTINCT al.template_id
    FROM access_logs al
  )
  GROUP BY tv.template_id
) AS template_versions_count;

SELECT title
FROM alert_templates
WHERE status = 'active';

SELECT COUNT(*) AS active_template_count
FROM alert_templates
WHERE status = 'active';

SELECT COUNT(incident_id) AS incident_count
FROM incident_types
WHERE category = 'meteorological';

SELECT COUNT(*) AS version_count
FROM template_versions
WHERE template_id = 0;

SELECT template_id, MAX(version_number) AS latest_version
FROM template_versions
GROUP BY template_id;

SELECT title
FROM alert_templates
ORDER BY created_date, template_id;

SELECT title
FROM alert_templates
ORDER BY template_id;
